import React, { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useSubscription } from '../contexts/SubscriptionContext';
import WorkoutCard from '../components/WorkoutCard';
import WorkoutProgress from '../components/WorkoutProgress';
import FavouriteExercises from '../components/FavouriteExercises';
// We're not using LoadingSpinner directly, so remove this import
// import LoadingSpinner from '../components/LoadingSpinner';
import EmptyState from '../components/EmptyState';
import DashboardGuide from './DashboardGuide';

const Dashboard = () => {
  const { user } = useAuth();
  const location = useLocation();
  
  // Only destructure what we're actually using
  const { 
    subscription, 
    formatTierName, 
    getValidUpgradeTiers, 
    forceRefreshSubscription 
  } = useSubscription();
  
  const [recommendedWorkouts, setRecommendedWorkouts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isError, setIsError] = useState(false);
  const [statusMessage, setStatusMessage] = useState(null);
  const [refreshing, setRefreshing] = useState(false);
  
  // Get valid upgrade options
  const upgradeOptions = getValidUpgradeTiers ? getValidUpgradeTiers() : ['premium', 'elite'];
  const currentTier = subscription?.tier || 'basic';
  
  // Track dashboard visit for analytics
  useEffect(() => {
    // This would normally call an analytics service
    console.log('Dashboard viewed by user:', user?.id);
  }, [user]);
  
  // Handle status messages from redirects (like from payment success)
  useEffect(() => {
    if (location.state?.message) {
      setStatusMessage({
        text: location.state.message,
        type: location.state.error ? 'error' : 'success'
      });
      
      // Clear message after 5 seconds
      const timer = setTimeout(() => {
        setStatusMessage(null);
      }, 5000);
      
      return () => clearTimeout(timer);
    }
  }, [location.state]);
  
  // Force refresh subscription data when component mounts - FIXED VERSION
  useEffect(() => {
    if (user) {
      console.log('Dashboard mounted, refreshing subscription data');
      const refreshData = async () => {
        try {
          setRefreshing(true);
          await forceRefreshSubscription();
        } catch (error) {
          console.error('Error refreshing subscription:', error);
        } finally {
          setRefreshing(false);
        }
      };
      
      refreshData();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]); // Remove forceRefreshSubscription from dependencies to prevent infinite loop
  
  // Fetch recommended workouts
  useEffect(() => {
    const getRecommendedWorkouts = async () => {
      try {
        setIsLoading(true);
        
        // Mock data for now - replace with actual API call
        const mockWorkouts = [
          {
            id: '1',
            title: 'Gentle Morning Stretch',
            duration: 15,
            difficulty: 'Beginner',
            imageUrl: '/images/gentle-stretch.jpg',
            description: 'Start your day with these gentle stretches to improve flexibility and mobility.'
          },
          {
            id: '2',
            title: 'Chair Strength Workout',
            duration: 20,
            difficulty: 'Beginner',
            imageUrl: '/images/chair-workout.jpg',
            description: 'Build strength while seated with this accessible workout.'
          },
          {
            id: '3',
            title: 'Balance Improvement',
            duration: 25,
            difficulty: 'Intermediate',
            imageUrl: '/images/balance.jpg',
            description: 'Exercises designed to improve stability and prevent falls.'
          }
        ];
        
        // Simulate network delay
        await new Promise(resolve => setTimeout(resolve, 800));
        
        setRecommendedWorkouts(mockWorkouts);
        setIsLoading(false);
      } catch (error) {
        console.error('Error fetching workouts:', error);
        setIsError(true);
        setIsLoading(false);
      }
    };
    
    getRecommendedWorkouts();
  }, [currentTier]);
  
  // Handle manual subscription refresh
  const handleRefreshSubscription = async () => {
    try {
      setRefreshing(true);
      await forceRefreshSubscription();
      setStatusMessage({
        text: 'Subscription data refreshed successfully',
        type: 'success'
      });
      
      // Clear message after 3 seconds
      setTimeout(() => {
        setStatusMessage(null);
      }, 3000);
    } catch (error) {
      console.error('Error refreshing subscription:', error);
      setStatusMessage({
        text: 'Failed to refresh subscription data',
        type: 'error'
      });
    } finally {
      setRefreshing(false);
    }
  };
  
  return (
    <div className="container mx-auto px-4 py-6">
      {/* Dashboard Guide component */}
      <DashboardGuide />
      
      {/* Status message alert */}
      {statusMessage && (
        <div className={`mb-6 p-4 rounded-md ${
          statusMessage.type === 'error' ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'
        }`}>
          <div className="flex">
            <div className="flex-shrink-0">
              {statusMessage.type === 'error' ? (
                <svg className="h-5 w-5 text-red-400" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                </svg>
              ) : (
                <svg className="h-5 w-5 text-green-400" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                </svg>
              )}
            </div>
            <div className="ml-3">
              <p className="text-sm font-medium">{statusMessage.text}</p>
            </div>
          </div>
        </div>
      )}
      
      {/* Check for server connection error */}
      {subscription?.error && (
        <div className="mb-6 p-4 bg-yellow-100 border border-yellow-400 text-yellow-700 rounded-md">
          <div className="flex">
            <div className="flex-shrink-0">
              <svg className="h-5 w-5 text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
            </div>
            <div className="ml-3">
              <p className="text-sm font-medium">
                <strong>Connection issue:</strong> {subscription.error}.
                Some features may be limited until connection is restored.
              </p>
            </div>
          </div>
        </div>
      )}
      
      <h1 className="text-3xl font-bold mb-6">Your Fitness Dashboard</h1>
      
      {/* Subscription Status Section */}
      <section className="mb-8 bg-gray-50 rounded-lg p-6 border border-gray-200">
        <div className="flex flex-col md:flex-row justify-between items-center">
          <div>
            <h2 className="text-xl font-semibold">
              Current Plan: <span className="text-indigo-600">{formatTierName(currentTier)}</span>
              {/* Enhanced refresh button with better feedback */}
              <button 
                onClick={handleRefreshSubscription}
                disabled={refreshing}
                className={`ml-2 px-3 py-1 text-xs border border-indigo-300 text-indigo-700 bg-indigo-50 rounded hover:bg-indigo-100 ${refreshing ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                {refreshing ? (
                  <span className="flex items-center">
                    <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-indigo-700" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Refreshing...
                  </span>
                ) : 'Refresh Plan Data'}
              </button>
            </h2>
            <p className="text-gray-600 mt-1">
              {currentTier === 'basic' 
                ? 'You are on our free Basic plan. Upgrade for more features!'
                : currentTier === 'premium'
                  ? 'You have access to our Premium features. Elite offers even more!'
                  : 'You have our top Elite plan with all features unlocked!'}
            </p>
          </div>
          
          {upgradeOptions.length > 0 && (
            <div className="mt-4 md:mt-0 flex flex-wrap gap-3">
              {upgradeOptions.map(tier => (
                <Link 
                  key={`upgrade-${tier}`}
                  to="/subscription/plans"
                  className={`px-4 py-2 rounded-md text-white font-medium ${
                    tier === 'premium' ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-purple-600 hover:bg-purple-700'
                  }`}
                >
                  Upgrade to {formatTierName(tier)}
                </Link>
              ))}
              
              <Link
                to="/subscription/manage"
                className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 font-medium"
              >
                Manage Subscription
              </Link>
            </div>
          )}
        </div>
        
        {/* Manual subscription update button for debugging/fixing */}
        <div className="mt-4 pt-4 border-t border-gray-200">
          <button
            onClick={() => {
              fetch('/api/stripe/manual-subscription-update', {
                method: 'POST',
                headers: {
                  'Content-Type': 'application/json',
                  'Authorization': `Bearer ${localStorage.getItem('token')}`
                },
                body: JSON.stringify({ tier: 'premium' })
              })
              .then(res => res.json())
              .then(data => {
                if (data.success) {
                  setStatusMessage({
                    text: 'Subscription manually updated to premium. Refreshing...',
                    type: 'success'
                  });
                  
                  // Force refresh subscription data
                  forceRefreshSubscription().then(() => {
                    console.log('Subscription data refreshed after manual update');
                  });
                }
              })
              .catch(err => {
                console.error('Failed to update subscription:', err);
                setStatusMessage({
                  text: 'Failed to update subscription. See console for details.',
                  type: 'error'
                });
              });
            }}
            className="text-sm px-3 py-1 bg-yellow-500 text-white rounded hover:bg-yellow-600"
          >
            Force Set Premium (Debug)
          </button>
        </div>
      </section>
      
      {/* Progress Section */}
      <section className="mb-10">
        <h2 className="text-2xl font-semibold mb-4">Your Progress</h2>
        <WorkoutProgress />
      </section>
      
      {/* Recommended Workouts Section */}
      <section className="mb-10">
        <h2 className="text-2xl font-semibold mb-4">Recommended Workouts</h2>
        {isLoading ? (
          <div className="flex justify-center py-12">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
          </div>
        ) : isError ? (
          <EmptyState 
            message="Unable to load workouts right now. Please try again later." 
            actionText="Retry"
            actionHandler={() => window.location.reload()} 
          />
        ) : recommendedWorkouts.length === 0 ? (
          <EmptyState 
            message="No workouts available yet. Complete your profile to get personalized recommendations." 
            actionText="Update Profile" 
            actionHandler={() => window.location.href = '/profile'} 
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {recommendedWorkouts.map(workout => (
              <WorkoutCard key={workout.id} workout={workout} />
            ))}
          </div>
        )}
      </section>
      
      {/* Favorite Exercises Section - only for Premium and Elite */}
      {currentTier !== 'basic' && (
        <section className="mb-10">
          <h2 className="text-2xl font-semibold mb-4">Your Favorite Exercises</h2>
          <FavouriteExercises />
        </section>
      )}
      
      {/* Upgrade Prompt - only for Basic tier */}
      {currentTier === 'basic' && (
        <section className="mb-10">
          <div className="bg-indigo-50 border border-indigo-200 rounded-lg p-6">
            <div className="flex flex-col md:flex-row items-center">
              <div className="md:flex-1">
                <h3 className="text-xl font-semibold text-indigo-800 mb-2">Unlock Premium Features!</h3>
                <p className="text-indigo-700 mb-4">
                  Upgrade to Premium or Elite to access personalized workout plans, video demonstrations, 
                  favorite exercise tracking, and more advanced features.
                </p>
                <ul className="space-y-2 mb-6">
                  <li className="flex items-start">
                    <svg className="h-5 w-5 text-indigo-500 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                    <span className="ml-2 text-indigo-700">Personalized workout recommendations</span>
                  </li>
                  <li className="flex items-start">
                    <svg className="h-5 w-5 text-indigo-500 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                    <span className="ml-2 text-indigo-700">Professional video demonstrations</span>
                  </li>
                  <li className="flex items-start">
                    <svg className="h-5 w-5 text-indigo-500 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                    <span className="ml-2 text-indigo-700">Track your favorite exercises</span>
                  </li>
                </ul>
              </div>
              <div className="md:ml-6 flex flex-col sm:flex-row gap-3">
                <Link 
                  to="/subscription/plans" 
                  className="px-6 py-3 bg-indigo-600 text-white rounded-md hover:bg-indigo-700 font-medium text-center"
                >
                  View Premium Plans
                </Link>
              </div>
            </div>
          </div>
        </section>
      )}
    </div>
  );
};

export default Dashboard;
